function normalizePerfil(perfil) {
  return String(perfil || "").replace("ROLE_", "").toUpperCase();
}

function isMasterPerfil(perfil) {
  return normalizePerfil(perfil) === "MASTER";
}

function isAdminPerfil(perfil) {
  return normalizePerfil(perfil) === "ADMIN";
}

function isPrivilegedPerfil(perfil) {
  return isAdminPerfil(perfil) || isMasterPerfil(perfil);
}

function normalizeStatus(status) {
  return String(status || "").trim().toUpperCase();
}

