      label: "Pacote real",
      value: fiscalRealConclusionSummary[0]?.value || 0,
      amount: fiscalRealConclusion
        .filter((item) => item.ready)
        .reduce((total, item) => total + Number(item.pedido?.valor || 0), 0),
