  async function handleDownloadFiscalXml(pedido) {
    const documento = getLatestFiscalDocument(pedido);
    if (!documento?.id || !documento?.possuiXmlEnvio) {
      setOrderMessage({ type: "error", text: "Este pedido ainda nao possui XML fiscal de homologacao gerado." });
      return;
    }

    setSavingOrderAction(`download-xml-${pedido.id}`);
    setOrderMessage(null);

    try {
      const documentoCompleto = await endpoints.fiscal.obterDocumento(documento.id);
      if (!documentoCompleto?.xmlEnvio) {
        setOrderMessage({ type: "error", text: "XML fiscal nao encontrado no documento atualizado." });
        return;
      }

      const filename = `nexus-one-${documentoCompleto.modelo || "documento-fiscal"}-${documentoCompleto.serie || "serie"}-${documentoCompleto.numero || pedido.id}.xml`;
      downloadTextFile(filename.toLowerCase(), documentoCompleto.xmlEnvio, "application/xml;charset=utf-8");
      setOrderMessage({ type: "success", text: "XML fiscal baixado." });
    } catch (error) {
      setOrderMessage({ type: "error", text: error.message || "Nao foi possivel baixar o XML fiscal." });
    } finally {
      setSavingOrderAction("");
    }
  }

