  async function handleConsultFiscalRealReadiness(pedido) {
    const documento = getLatestFiscalDocument(pedido);
    if (!documento?.id) {
      setOrderMessage({ type: "error", text: "Este pedido ainda nao possui documento fiscal para status real." });
      return;
    }

    const actionKey = `status-real-${pedido.id}`;
    setSavingOrderAction(actionKey);
    setOrderMessage(null);

    try {
      const status = await endpoints.fiscal.statusEmissaoReal(documento.id);
      const pendencias = asList(status.pendencias);
      const resumoPendencias = pendencias.slice(0, 3).join(" | ");
      const totalPendencias = Number.isFinite(Number(status.totalPendencias))
        ? Number(status.totalPendencias)
        : pendencias.length;
      const totalExternas = Number.isFinite(Number(status.totalPendenciasExternas))
        ? Number(status.totalPendenciasExternas)
        : asList(status.pendenciasExternas).length;
      const alertaExterno = totalExternas > 0 ? ` Validar ${formatNumber(totalExternas)} item(ns) externo(s).` : "";
      setOrderMessage({
        type: status.prontoEmissaoReal ? "success" : "error",
        text: status.prontoEmissaoReal
          ? `${status.documento || "Documento fiscal"}: prontidao real ${status.percentualProntidao || 0}%. ${status.proximaAcao || "Checklist sem bloqueios operacionais."}${alertaExterno}`
          : `${status.documento || "Documento fiscal"}: prontidao real ${status.percentualProntidao || 0}%, bloqueada por ${formatNumber(totalPendencias || 1)} pendencia(s): ${resumoPendencias || status.proximaAcao || "consulte o checklist real."}${alertaExterno}`,
      });
    } catch (error) {
      setOrderMessage({ type: "error", text: error.message || "Nao foi possivel consultar o status de emissao real." });
    } finally {
      setSavingOrderAction("");
    }
  }

  async function handleDownloadFiscalRealPackage(pedido) {
    const documento = getLatestFiscalDocument(pedido);
    if (!documento?.id) {
      setOrderMessage({ type: "error", text: "Este pedido ainda nao possui documento fiscal para pacote real." });
      return;
    }

    setSavingOrderAction(`download-pacote-real-${pedido.id}`);
    setOrderMessage(null);

    try {
      const pacote = await endpoints.fiscal.pacoteEmissaoReal(documento.id);
      const pendencias = asList(pacote.pendencias);
      const resumoPendencias = pendencias.slice(0, 3).join(" | ");
      const totalPendencias = Number.isFinite(Number(pacote.totalPendencias))
        ? Number(pacote.totalPendencias)
        : pendencias.length;
      const totalExternas = Number.isFinite(Number(pacote.totalPendenciasExternas))
        ? Number(pacote.totalPendenciasExternas)
        : asList(pacote.pendenciasExternas).length;
      const alertaExterno = totalExternas > 0 ? ` Validar ${formatNumber(totalExternas)} item(ns) externo(s).` : "";
      const filename = `nexus-one-pacote-emissao-real-${documento.modelo || "documento-fiscal"}-${documento.serie || "serie"}-${documento.numero || pedido.id}.json`;
      downloadTextFile(filename.toLowerCase(), JSON.stringify(pacote, null, 2), "application/json;charset=utf-8");
      setOrderMessage({
        type: pacote.prontoEmissaoReal ? "success" : "error",
        text: pacote.prontoEmissaoReal
          ? `Pacote de emissao real baixado. Prontidao ${pacote.percentualProntidao || 0}%.${alertaExterno}`
          : `Pacote real baixado com ${formatNumber(totalPendencias || 1)} pendencia(s). Prontidao ${pacote.percentualProntidao || 0}%. ${pacote.proximaAcao || resumoPendencias || "Consulte o checklist real."}${alertaExterno}`,
      });
    } catch (error) {
      setOrderMessage({ type: "error", text: error.message || "Nao foi possivel baixar o pacote de emissao real." });
    } finally {
      setSavingOrderAction("");
    }
  }

  async function handleDownloadFiscalRealPackageManifest(pedido) {
    const documento = getLatestFiscalDocument(pedido);
    if (!documento?.id) {
      setOrderMessage({ type: "error", text: "Este pedido ainda nao possui documento fiscal para manifesto." });
      return;
    }

    setSavingOrderAction(`download-manifesto-real-${pedido.id}`);
    setOrderMessage(null);

    try {
      const content = await endpoints.fiscal.manifestoPacoteEmissaoReal(documento.id);
      const filename = `nexus-one-manifesto-pacote-real-${documento.modelo || "documento-fiscal"}-${documento.serie || "serie"}-${documento.numero || pedido.id}.txt`;
      downloadTextFile(filename.toLowerCase(), content);
      setOrderMessage({ type: "success", text: "Manifesto de integridade do pacote real baixado." });
    } catch (error) {
      setOrderMessage({ type: "error", text: error.message || "Nao foi possivel baixar o manifesto do pacote real." });
    } finally {
      setSavingOrderAction("");
    }
  }

  async function handleValidateFiscalRealPackageIntegrity(pedido) {
    const documento = getLatestFiscalDocument(pedido);
    if (!documento?.id) {
      setOrderMessage({ type: "error", text: "Este pedido ainda nao possui documento fiscal para validar pacote." });
      return;
    }

    setSavingOrderAction(`validar-pacote-real-${pedido.id}`);
    setOrderMessage(null);

    try {
      const integridade = await endpoints.fiscal.validarIntegridadePacoteEmissaoReal(documento.id);
      const pendencias = asList(integridade.pendencias);
      const totalPendencias = Number.isFinite(Number(integridade.totalPendencias))
        ? Number(integridade.totalPendencias)
        : pendencias.length;
      const prontidao = Number.isFinite(Number(integridade.percentualProntidao))
        ? ` Prontidao ${formatNumber(integridade.percentualProntidao)}%.`
        : "";
      setOrderMessage({
        type: integridade.valido ? "success" : "error",
        text: integridade.valido
          ? `Pacote real integro: ${integridade.pacoteReferencia || "referencia gerada"}.${prontidao} ${integridade.proximaAcao || ""}`.trim()
          : `Pacote real bloqueado por ${formatNumber(totalPendencias || 1)} pendencia(s).${prontidao} ${integridade.proximaAcao || pendencias.slice(0, 3).join(" | ") || "verifique payload/XML e checklist real"}`,
      });
    } catch (error) {
      setOrderMessage({ type: "error", text: error.message || "Nao foi possivel validar a integridade do pacote real." });
    } finally {
      setSavingOrderAction("");
    }
  }

  async function handleDownloadFiscalPendencies(pedido) {
    const documento = getLatestFiscalDocument(pedido);
    if (!documento?.id || !documento?.possuiPendenciasFiscais) {
      setOrderMessage({ type: "error", text: "Este pedido nao possui pendencias fiscais registradas." });
      return;
    }

    setSavingOrderAction(`download-pendencias-${pedido.id}`);
    setOrderMessage(null);

    try {
      const documentoCompleto = await endpoints.fiscal.obterDocumento(documento.id);
      if (!documentoCompleto?.pendenciasFiscais) {
        setOrderMessage({ type: "error", text: "Pendencias fiscais nao encontradas no documento atualizado." });
        return;
      }

      const filename = `nexus-one-pendencias-fiscais-${documentoCompleto.modelo || "documento-fiscal"}-${documentoCompleto.serie || "serie"}-${documentoCompleto.numero || pedido.id}.txt`;
      const content = [
        "PENDENCIAS FISCAIS - NEXUS ONE",
        `Pedido: ${pedido.numero || pedido.id || "-"}`,
        `Documento: ${documentoCompleto.modelo || "-"} ${documentoCompleto.serie || "-"}-${documentoCompleto.numero || "-"}`,
        "",
        documentoCompleto.pendenciasFiscais,
      ].join("\n");
      downloadTextFile(filename.toLowerCase(), content);
      setOrderMessage({ type: "success", text: "Pendencias fiscais baixadas." });
    } catch (error) {
      setOrderMessage({ type: "error", text: error.message || "Nao foi possivel baixar as pendencias fiscais." });
    } finally {
      setSavingOrderAction("");
    }
  }

